BEGIN TRANSACTION;

-- Complete the sr_meta -> T2 canonicalization for systematic reviews / meta-analyses
-- that the 2026-05-25 migration (data_20260525070000_sr_meta_t2_canonicalization.sql)
-- could not reach. That migration's WHERE clause was `evidence_type = 'sr_meta' AND
-- tier = 3`, so it only re-tiered rows ALREADY typed sr_meta. The 13 rows below are
-- genuine systematic reviews / meta-analyses that were mis-typed at the evidence_type
-- level ('clinical' or 'grey') and therefore stayed at T3 in violation of the enshrined
-- rule (governance/tier-system.md §2: "systematic reviews and meta-analyses sit at
-- Tier 2"; owner directive 2026-05-25 "t2>t3 this is enshrined").
--
-- Each row self-identifies as a systematic review / meta-analysis in its own title or
-- subtitle. Five were independently re-verified this session via a real tool call
-- (anti-fabrication / classification gate):
--   REF-00398  WebFetch mdpi.com/2571-631X/4/2/29 — "A Systematic Review", PRISMA-style, Larivière et al. 2021
--   REF-00097  PubMed PMID 36082841 — "systematic review" publication type
--   REF-00240  PubMed PMID 28990665 — "systematic review" publication type
--   REF-00642  WebSearch tandfonline 10.1080/13603116.2025.2589290 — SR, 4 databases / 23 studies
--   REF-00570  WebSearch pubs.asha.org 10.1044/2022_LSHSS-21-00181 — SR, PubMed+Scopus / 23 studies
-- The remaining eight carry an explicit "Systematic Review" / "Meta-analysis" self-label
-- in their already-VERIFIED stored title and are reclassified on that basis.
--
-- Scope guard: SCOPING reviews are methodologically distinct from systematic reviews
-- (breadth-mapping without critical-appraisal synthesis) and are NOT covered by the
-- 2026-05-25 directive. REF-00069 ("rapid systematic review") trades systematic rigour
-- for speed and is likewise ambiguous. None of those nine rows are touched here; the
-- tier-placement decision for them is logged as GAP-298 (DEC) for owner adjudication.

-- ── 1. Reclassify the 13 confirmed systematic reviews / meta-analyses to T2 sr_meta ──
UPDATE evidence_sources
   SET tier = 2,
       evidence_type = 'sr_meta',
       verification_note = COALESCE(verification_note || ' ', '') ||
         '[SR-META TIER RECONCILIATION 2026-07-20] Reclassified clinical/grey T3 -> sr_meta T2: ' ||
         'source self-identifies as a systematic review / meta-analysis; enshrined placement is T2 ' ||
         '(governance/tier-system.md §2). Completes the 2026-05-25 canonicalization, whose WHERE ' ||
         'clause reached only already-sr_meta-typed rows. Not caught then because evidence_type was ' ||
         'mis-set to clinical/grey. See GAP-298 note and session_2026-07-20-sr-meta-tier-reconciliation.md.',
       updated_at = '2026-07-20T05:00:00Z',
       updated_by_session = 'session_2026-07-20-sr-meta-tier-reconciliation'
 WHERE ref_id IN (
   'REF-00097','REF-00227','REF-00240','REF-00256','REF-00398','REF-00570',
   'REF-00589','REF-00607','REF-00611','REF-00637','REF-00638','REF-00639','REF-00642'
 )
   AND tier = 3;

